package com.baize.flux.server.runtime;
import java.util.*;
/** REST 可安全序列化的不可变作业视图。 */
public final class JobSnapshot {
 private final String jobId,jobName,errorCode,errorMessage; private final ServerJobStatus status; private final long createTimeMillis,startTimeMillis,endTimeMillis; private final Map<String,Object> metrics,commitSummary; private final List<Map<String,Object>> pipelines;
 public JobSnapshot(String id,String name,ServerJobStatus status,long create,long start,long end,Map<String,Object> metrics,Map<String,Object> commit,List<Map<String,Object>> pipelines,String code,String message){this.jobId=id;this.jobName=name;this.status=status;this.createTimeMillis=create;this.startTimeMillis=start;this.endTimeMillis=end;this.metrics=Collections.unmodifiableMap(new LinkedHashMap<String,Object>(metrics));this.commitSummary=Collections.unmodifiableMap(new LinkedHashMap<String,Object>(commit));this.pipelines=Collections.unmodifiableList(new ArrayList<Map<String,Object>>(pipelines));this.errorCode=code;this.errorMessage=message;}
 public String getJobId(){return jobId;} public String getJobName(){return jobName;} public ServerJobStatus getStatus(){return status;} public long getCreateTimeMillis(){return createTimeMillis;} public long getStartTimeMillis(){return startTimeMillis;} public long getEndTimeMillis(){return endTimeMillis;} public long getDurationMillis(){return startTimeMillis==0?0:Math.max(0,(endTimeMillis==0?System.currentTimeMillis():endTimeMillis)-startTimeMillis);} public Map<String,Object> getMetrics(){return metrics;} public Map<String,Object> getCommitSummary(){return commitSummary;} public List<Map<String,Object>> getPipelines(){return pipelines;} public String getErrorCode(){return errorCode;} public String getErrorMessage(){return errorMessage;}
}
